import {Collection, CollectionStateBase, Node} from '@react-types/shared';
import {CollectionBuilder} from './CollectionBuilder';
import {ReactElement, useMemo} from 'react';

interface CollectionOptions<T, C extends Collection<Node<T>>> extends Omit<
  CollectionStateBase<T, C>,
  'children'
> {
  children?:
    | ReactElement<any>
    | null
    | (ReactElement<any> | null)[]
    | ((item: T) => ReactElement<any> | null);
}

type CollectionFactory<T, C extends Collection<Node<T>>> = (node: Iterable<Node<T>>) => C;

export function useCollection<T, C extends Collection<Node<T>> = Collection<Node<T>>>(
  props: CollectionOptions<T, C>,
  factory: CollectionFactory<T, C>,
  context?: unknown
): C {
  let builder = useMemo(() => new CollectionBuilder<any>(), []);
  let {children, items, collection} = props;
  let result = useMemo(() => {
    if (collection) {
      return collection;
    }
    let nodes = builder.build({children, items}, context);
    return factory(nodes);
  }, [builder, children, items, collection, context, factory]);
  return result;
}
